function solve(nums, queries) {
    class FenwickTree {
        constructor(size) {
            this.n = size;
            this.tree = new Array(this.n + 1).fill(0);
        }
        update(index, delta) {
            while (index <= this.n) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }
        query(index) {
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }
        rangeQuery(l, r) {
            return this.query(r) - this.query(l - 1);
        }
    }

    function countSetBits(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    function getDepth(x) {
        let depth = 0;
        while (x !== 1) {
            x = countSetBits(x);
            depth++;
        }
        return depth;
    }

    const n = nums.length;
    const depths = new Array(n);
    for (let i = 0; i < n; i++) {
        depths[i] = getDepth(nums[i]);
    }

    const bitDepth0 = new FenwickTree(n);
    const bitDepth1 = new FenwickTree(n);
    const bitDepth2 = new FenwickTree(n);
    const bitDepth3 = new FenwickTree(n);

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        if (d === 0) {
            bitDepth0.update(i + 1, 1);
        } else if (d === 1) {
            bitDepth1.update(i + 1, 1);
        } else if (d === 2) {
            bitDepth2.update(i + 1, 1);
        } else if (d === 3) {
            bitDepth3.update(i + 1, 1);
        }
    }

    const answer = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            let res = 0;
            if (k >= 0 && k <= 3) {
                if (k === 0) {
                    res = bitDepth0.rangeQuery(l + 1, r + 1);
                } else if (k === 1) {
                    res = bitDepth1.rangeQuery(l + 1, r + 1);
                } else if (k === 2) {
                    res = bitDepth2.rangeQuery(l + 1, r + 1);
                } else if (k === 3) {
                    res = bitDepth3.rangeQuery(l + 1, r + 1);
                }
            }
            answer.push(res);
        } else {
            const [_, idx, val] = query;
            const oldVal = nums[idx];
            const oldDepth = depths[idx];
            if (oldDepth === 0) {
                bitDepth0.update(idx + 1, -1);
            } else if (oldDepth === 1) {
                bitDepth1.update(idx + 1, -1);
            } else if (oldDepth === 2) {
                bitDepth2.update(idx + 1, -1);
            } else if (oldDepth === 3) {
                bitDepth3.update(idx + 1, -1);
            }
            nums[idx] = val;
            const newDepth = getDepth(val);
            if (newDepth === 0) {
                bitDepth0.update(idx + 1, 1);
            } else if (newDepth === 1) {
                bitDepth1.update(idx + 1, 1);
            } else if (newDepth === 2) {
                bitDepth2.update(idx + 1, 1);
            } else if (newDepth === 3) {
                bitDepth3.update(idx + 1, 1);
            }
        }
    }

    return answer;
}

