            this.n = size;
            this.tree = new Array(this.n + 1).fill(0);
        }
        update(index, delta) {
            while (index <= this.n) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }
        query(index) {
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }
        rangeQuery(l, r) {
            return this.query(r) - this.query(l - 1);
        }
    }

    function countSetBits(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

