class FenwickTree(val size: Int) {
    private val tree: LongArray
    init {
        tree = LongArray(size + 1)
    }
    fun update(index: Int, delta: Long) {
        var i = index
        while (i <= size) {
            tree[i] += delta
            i += i and -i
        }
    }
    fun query(index: Int): Long {
        var res = 0L
        var i = index
        while (i > 0) {
            res += tree[i]
            i -= i and -i
        }
        return res
    }
    fun rangeQuery(l: Int, r: Int): Long {
        return query(r) - query(l - 1)
    }
}

